import { describe, expect, it } from '@a0n/gnosis/test';
import { CACHE_OBSERVATION_LEAN_MODULE } from './esc/cache-observation';
import {
  EscMemoryTier,
  type EscTier,
  type EscWasmSegmentRecord,
} from './esc/edge-side-compute';
import {
  GnosisWasmExecutionSurface,
  type GnosisWasmTopologyAdmission,
  type WasmExecutionControlResponse,
  type WasmExecutionResponse,
  type WasmExecutionSurfaceStatus,
} from './wasm-execution';
import { dnaToKnot } from './runtime/packed-knot';

const WASM_DOUBLE_FIXTURE_BASE64 =
  '';

const PROVEN_TOPOLOGY_ADMISSION: GnosisWasmTopologyAdmission = {
  topologyCoordinates: [10, 12, 17, 22, 43],
  gateCoordinates: [10, 12, 17, 22],
  decompositionCoordinates: [7, 17, 22],
  interferePort: {
    action: 'interfere',
    coordinate: 43,
    closureCoordinate: 55,
    terminal: true,
  },
  pressureWeightedInterference: {
    strideTrace: [33, 31, 26, 21],
    leakagePressureTrace: [0, 18, 78],
    pressureWeightedStrideTrace: [0, 558, 2028],
    pressureWeightedTotal: 2586,
    pressureUnit: 'SPa',
  },
  theoremIds: [
    'GamutBraid.exact_pressure_weighted_interference_anchor_packet_certified',
    'StatisticalMechanicsAccounting.exact_total_information_mass',
    'StatisticalMechanicsAccounting.exact_total_leakage',
  ],
};

function encodeJson(value: unknown): Uint8Array {
  return new TextEncoder().encode(JSON.stringify(value));
}

function decodeJson<T>(response: WasmExecutionControlResponse): T {
  return JSON.parse(new TextDecoder().decode(response.body)) as T;
}

describe('GnosisWasmExecutionSurface', () => {
  it('registers and executes a wasm artifact directly', async () => {
    const surface = new GnosisWasmExecutionSurface();
    const artifact = surface.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });

    const execution = await surface.execute({
      artifactId: artifact.artifactId,
      input: 21,
    });
    const status = surface.getStatus();

    expect(execution.payload).toBe(42);
    expect(execution.abi).toBe('scalar-v1');
    expect(status.registeredArtifacts).toBe(1);
    expect(status.artifacts[0]?.artifactId).toBe(artifact.artifactId);
  });

  it('reports proven topology admission on status and execution', async () => {
    const surface = new GnosisWasmExecutionSurface({
      topologyAdmission: PROVEN_TOPOLOGY_ADMISSION,
    });
    const artifact = surface.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });

    const execution = await surface.execute({
      artifactId: artifact.artifactId,
      input: 11,
    });
    const status = surface.getStatus();

    expect(execution.payload).toBe(22);
    expect(execution.topologyAdmissionFingerprint).toMatch(/^[0-9a-f]{24}$/);
    expect(status.topologyAdmission?.topologyCoordinates).toEqual([
      10, 12, 17, 22, 43,
    ]);
    expect(status.topologyAdmission?.gateCoordinates).toEqual([
      10, 12, 17, 22,
    ]);
    expect(status.topologyAdmission?.interferePort?.coordinate).toBe(43);
  });

  it('serves status, register, and execute control routes', async () => {
    const surface = new GnosisWasmExecutionSurface({
      enabled: true,
      runtimeBindingHash:
        'binding-wasm-runtime-0123456789abcdef0123456789abcdef',
    });

    const registerResponse = await surface.handleRequest({
      method: 'POST',
      path: '/.aeon/wasm/register',
      body: encodeJson({
        wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
        exportName: 'double_value',
        abi: 'scalar-v1',
      }),
    });

    expect(registerResponse?.status).toBe(200);
    const registered = decodeJson<{ artifactId: string }>(registerResponse!);
    expect(registered.artifactId.length).toBeGreaterThan(0);

    const executeResponse = await surface.handleRequest({
      method: 'POST',
      path: '/.aeon/wasm/execute',
      headers: {
        'x-aeon-auth-verified': '1',
        'x-aeon-actor': 'did:key:wasm-runner',
        'x-ucan-capabilities': 'gnosis/wasm.run,aeon/process',
      },
      body: encodeJson({
        artifactId: registered.artifactId,
        input: 9,
      }),
    });

    expect(executeResponse?.status).toBe(200);
    const execution = decodeJson<WasmExecutionResponse>(executeResponse!);
    expect(execution.payload).toBe(18);
    expect(execution.abi).toBe('scalar-v1');
    expect(execution.executionAuth?.enforced).toBe(true);
    expect(execution.executionAuth?.principal).toBe('did:key:wasm-runner');
    expect(execution.executionAuth?.capabilityCount).toBe(2);
    expect(execution.executionAuth?.reactorHandleGrantCount).toBe(2);
    expect(execution.executionAuth?.reactorHandleKinds).toEqual([
      'request',
      'response',
    ]);
    expect(execution.executionAuth?.source).toBe('headers');

    const statusResponse = await surface.handleRequest({
      method: 'GET',
      path: '/.aeon/wasm/status',
    });

    expect(statusResponse?.status).toBe(200);
    const status = decodeJson<WasmExecutionSurfaceStatus>(statusResponse!);
    expect(status.enabled).toBe(true);
    expect(status.registeredArtifacts).toBe(1);
    expect(status.artifacts[0]?.source).toBe('inline');
  });

  it('teleports declared-pure WASM via ESC tier when auth is absent', async () => {
    const mem = new EscMemoryTier();
    const escCalls = { get: 0, set: 0 };
    const escTier: EscTier = {
      async get(key: string): Promise<EscWasmSegmentRecord | null> {
        escCalls.get += 1;
        return mem.get(key);
      },
      async set(key: string, record: EscWasmSegmentRecord): Promise<void> {
        escCalls.set += 1;
        await mem.set(key, record);
      },
    };

    const surface = new GnosisWasmExecutionSurface({
      escTier,
      runtimeBindingHash: 'wasm-esc-test-binding',
    });
    const artifact = surface.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });

    const knotSlice = dnaToKnot('GT');

    const first = await surface.execute({
      artifactId: artifact.artifactId,
      input: 5,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
        policySalt: 'tenant-a',
      },
    });
    expect(first.payload).toBe(10);
    expect(first.escObservation?.formalRef).toBe(CACHE_OBSERVATION_LEAN_MODULE);
    expect(first.escObservation?.resolution.kind).toBe('cold_miss');
    expect(first.escObservation?.marginalFoldWork).toBe(1);

    const second = await surface.execute({
      artifactId: artifact.artifactId,
      input: 5,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
        policySalt: 'tenant-a',
      },
    });
    expect(second.payload).toBe(10);
    expect(second.escObservation?.resolution.kind).toBe('hit');
    expect(second.escObservation?.marginalFoldWork).toBe(0);
    expect(escCalls.set).toBe(1);
    expect(escCalls.get).toBe(2);
    expect(mem.size).toBe(1);
  });

  it('binds ESC pure cache keys to topology admission fingerprint', async () => {
    const mem = new EscMemoryTier();
    const escCalls = { get: 0, set: 0 };
    const escTier: EscTier = {
      async get(key: string): Promise<EscWasmSegmentRecord | null> {
        escCalls.get += 1;
        return mem.get(key);
      },
      async set(key: string, record: EscWasmSegmentRecord): Promise<void> {
        escCalls.set += 1;
        await mem.set(key, record);
      },
    };
    const withTopology = new GnosisWasmExecutionSurface({
      escTier,
      topologyAdmission: PROVEN_TOPOLOGY_ADMISSION,
    });
    const withoutTopology = new GnosisWasmExecutionSurface({ escTier });
    const withTopologyArtifact = withTopology.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });
    const withoutTopologyArtifact = withoutTopology.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });
    const knotSlice = dnaToKnot('GT');

    const first = await withTopology.execute({
      artifactId: withTopologyArtifact.artifactId,
      input: 7,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
      },
    });
    const second = await withoutTopology.execute({
      artifactId: withoutTopologyArtifact.artifactId,
      input: 7,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
      },
    });
    const third = await withTopology.execute({
      artifactId: withTopologyArtifact.artifactId,
      input: 7,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
      },
    });

    expect(first.escObservation?.resolution.kind).toBe('cold_miss');
    expect(first.topologyAdmissionFingerprint).toMatch(/^[0-9a-f]{24}$/);
    expect(second.escObservation?.resolution.kind).toBe('cold_miss');
    expect(second.topologyAdmissionFingerprint).toBeUndefined();
    expect(third.escObservation?.resolution.kind).toBe('hit');
    expect(third.topologyAdmissionFingerprint).toBe(
      first.topologyAdmissionFingerprint
    );
    expect(escCalls.set).toBe(2);
    expect(mem.size).toBe(2);
  });

  it('ESC stale path re-executes and reports stale_miss marginal work', async () => {
    const escTier = new EscMemoryTier();
    const surface = new GnosisWasmExecutionSurface({ escTier });
    const artifact = surface.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });
    const knotSlice = dnaToKnot('AC');

    const cold = await surface.execute({
      artifactId: artifact.artifactId,
      input: 2,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
        missFoldWork: 5,
      },
    });
    expect(cold.escObservation?.resolution.kind).toBe('cold_miss');
    expect(cold.escObservation?.marginalFoldWork).toBe(5);

    const stale = await surface.execute({
      artifactId: artifact.artifactId,
      input: 2,
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
        missFoldWork: 5,
        cacheEntryValid: false,
      },
    });
    expect(stale.payload).toBe(4);
    expect(stale.escObservation?.resolution.kind).toBe('stale_miss');
    expect(stale.escObservation?.marginalFoldWork).toBe(5);
  });

  it('does not use ESC when executionAuth is present', async () => {
    const escTier = new EscMemoryTier();
    const surface = new GnosisWasmExecutionSurface({ escTier });
    const artifact = surface.register({
      wasmBase64: WASM_DOUBLE_FIXTURE_BASE64,
      exportName: 'double_value',
      abi: 'scalar-v1',
    });
    const knotSlice = dnaToKnot('A');

    await surface.execute({
      artifactId: artifact.artifactId,
      input: 3,
      executionAuth: {
        principal: 'did:key:test',
        capabilities: [],
        enforce: true,
      },
      esc: {
        mode: 'pure',
        knotSlice,
        entryCrossingIndex: 0,
      },
    });

    expect(escTier.size).toBe(0);
  });
});
